import React from 'react'
import { CHeader, CContainer,CHeaderBrand, CHeaderNav, CHeaderToggler,  CDropdown, CDropdownToggle, CDropdownMenu, CDropdownItem  } from '@coreui/react';


const ProfileDropdown = () => {

    const [visible, setVisible] = useState(false);

    return (
        <CDropdown visible={visible} onVisibleChange={setVisible} className="profile-dropdown">
            <CDropdownToggle className="p-0 border-0 bg-transparent">
                <img
                    src={"https://ui-avatars.com/api/?name=Dheeraj+Khanna"}
                    alt="User"
                    className="rounded-circle"
                    width="36"
                    height="36"
                    style={{ objectFit: 'cover' }}
                />
            </CDropdownToggle>
            <CDropdownMenu className="pt-0">
                <CDropdownItem href="#">Profile</CDropdownItem>
                <CDropdownItem href="#">Settings</CDropdownItem>
                <CDropdownItem href="#">Logout</CDropdownItem>
            </CDropdownMenu>
        </CDropdown>
    );
};

export default ProfileDropdown;
